def bead_sort(seq):
    for _ in range(len(seq)):
        for i, (upper, lower) in enumerate(zip(seq, seq[1:])):
            if upper > lower:
                diff = upper - lower
                seq[i] -= diff
                seq[i+1] += diff
    return seq

if __name__ == "__main__":
    print(f"Sorted: {bead_sort([5, 4, 3, 2, 1])}")
